# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).
# Category: path_traversal

using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

namespace YourNamespace.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class FilesController : ControllerBase
    {
        // GET api/files/{filename}
        [HttpGet("{fileName}")]
        public async Task<IActionResult> Get(string fileName)
        {
            if (!System.IO.File.Exists(@"Uploads\" + fileName)) 
                return NotFound(); // Return 404 Not Found if the file does not exist
            
            var memoryStream = new MemoryStream();  
            await System.IO.File.OpenRead(@"Uploads\" + fileName).CopyToAsync(memoryStream); // Read the uploaded file into a stream
            string contentType;
            
            switch (Path.GetExtension(fileName))  // Determine the Content Type of the File by looking at its Extension
            {
                case ".pdf":
                    contentType = "application/pdf";
                    break;
                
                case ".docx":
                case ".doc":
                    contentType = "application/msword";
                    break;
                
                case ".jpg":
                case ".png":
                case ".gif":
                    contentType = "image/" + Path.GetExtension(fileName).Replace(".", "");  // return the image based on its type (e.g jpg returns 'image/jpeg')
                    
                default:
                    contentType = ""; // Handle unrecognized file types here if required or throw an error response
            }
            
            memoryStream.Position = 0;  
            Response.ContentType = contentType;  // Set the Content-Type Header of the HttpResponse according to the File Type
                
            return new FileStreamResult(memoryStream, Response.ContentType); // Return the file as a FileStreamResult (which is essentially a HTTP response that contains the file data)  
        }
    }
}